INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In September 2023, which country claimed to have successfully launched an imaging satellite Noor-3 into space?', 'Iran', 'Turkey', 'Saudi Arabia', 'Qatar', 1, 'Iran successfully launched the Noor-3 imaging satellite in September 2023, marking another milestone in its space program.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'León Marchand, who made news with his record-breaking performance, is associated with which of the following sports?', 'Chess', 'Swimming', 'Boxing', 'Tennis', 2, 'Léon Marchand is a French swimmer who broke Michael Phelps'' world record in the 400m individual medley at the 2023 World Championships.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Where was India''s first 3D printed post office inaugurated in August 2023?', 'Ahmedabad', 'Mumbai', 'Hyderabad', 'Bengaluru', 3, 'India''s first 3D printed post office was inaugurated in Bengaluru (Cambridge Layout) in August 2023, constructed using 3D printing technology.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following vehicle successfully launched Chandrayaan-3 into orbit?', 'LVM3 M4', 'PSLV-C57', 'PSLV-C48', 'GSLV Mk II', 1, 'Chandrayaan-3 was launched on July 14, 2023, using the LVM3-M4 (Launch Vehicle Mark-3) rocket from Satish Dhawan Space Centre.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'GPS Aided Geo Augmented Navigation (GAGAN) has been developed as a regional Satellite Based Augmentation System (SBAS) by ______. I. Airports Authority of India (AAI) II. Indian Space Research Organization (ISRO)', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'GAGAN was developed jointly by AAI and ISRO to provide accurate GPS navigation signals for aviation and other applications.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'As of November 2023, researchers from ______ have developed a new artificial light-harvesting system that can efficiently capture light for power conversion by mimicking photosynthesis. I. IISER-Thiruvananthapuram II. IIT-Indore', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Researchers from IISER-Thiruvananthapuram developed the artificial light-harvesting system mimicking photosynthesis for efficient power conversion.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding e-Krishi Samvad? I. This internet-based interface was launched in 2017. II. This is a unique platform that provides direct and effective solutions to the problems faced by farmers and stakeholders in the agriculture sector.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'e-Krishi Samvad was launched in 2016 (not 2017). Statement I is incorrect. It is indeed a unique platform providing solutions to farmers, so Statement II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In November 2021, ______, under the aegis of Ministry of Education, conducted the National Achievement Survey throughout the country.', 'CBSE', 'NCERT', 'AICTE', 'ITI', 2, 'NCERT conducted the National Achievement Survey (NAS) in November 2021 under the Ministry of Education to assess learning outcomes of students.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'One Stop Centre (OSC) Scheme is implemented by which Ministry of the Government of India?', 'Ministry of Health and Family Welfare', 'Ministry of Women and Child Development', 'Ministry of Road Transport and Highways', 'Ministry of Social Justice and Empowerment', 2, 'The One Stop Centre (OSC) Scheme, also known as Sakhi, is implemented by the Ministry of Women and Child Development to support women affected by violence.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Pradhan Mantri Shram Yogi Maandhan is a government scheme meant for which of the following? I. Old age protection II. Social security of Unorganized workers', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'PM Shram Yogi Maandhan provides old age protection and social security to unorganized workers through a monthly pension after age 60.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following Goals of the 2030 Agenda for Sustainable Development seeks to ensure inclusive and equitable quality education and promote lifelong learning opportunities for all?', 'Goal 3', 'Goal 4', 'Goal 5', 'Goal 6', 2, 'Sustainable Development Goal 4 (SDG 4) aims to ensure inclusive and equitable quality education and promote lifelong learning opportunities for all.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In November 2021, the Government of India Constituted a High-Level Committee to develop a National Credit Accumulation & Transfer Framework for both Vocational and General Education under the chairmanship of ______.', 'Neelam Shammi Rao', 'Sridhar Srivastava', 'Manoj Ahuja', 'Nirmaljeet Singh Kalsi', 4, 'The High-Level Committee for National Credit Accumulation & Transfer Framework was chaired by Nirmaljeet Singh Kalsi in November 2021.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'In the context of the National Education Policy 2020, which of the following statements is/are correct regarding the new pedagogical and curricular structure? I. A strong base of Early Childhood Care and Education from age 3 is included in the 5+3+3+4 structure. II. A National Mission on Foundational Literacy and Numeracy will be set up by the Ministry of Human Resource Development.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: NEP 2020 introduces 5+3+3+4 structure with ECCE from age 3, and establishes a National Mission on Foundational Literacy and Numeracy.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'The Asian Games 2023 was held in ______.', 'Shenzhen', 'Hangzhou', 'Guangzhou', 'Chongqing', 2, 'The 19th Asian Games 2023 were held in Hangzhou, China from September to October 2023.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'The Indian men''s hockey team won the Asian Champions Trophy 2023 after defeating ______ in the final.', 'Malaysia', 'Japan', 'Korea', 'Pakistan', 1, 'India defeated Malaysia 4-3 in the final of the Asian Champions Trophy 2023 held in Chennai.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Sagar Kailas Owhalkar is associated with which of the following sports?', 'Badminton', 'Kabaddi', 'Shooting', 'Mallakhamb', 4, 'Sagar Kailas Owhalkar is a renowned Mallakhamb athlete, a traditional Indian sport involving gymnastics on a pole or rope.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Who was honoured with the Tenzing Norgay National Adventure Award in the Water Adventure category for the year 2021?', 'Naina Dhakad', 'Shubham Dhananjay Vanmali', 'Kunwar Bhawani Singh Samyal', 'Priyanka Mohite', 2, 'Shubham Dhananjay Vanmali received the Tenzing Norgay National Adventure Award 2021 in the Water Adventure category.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of National Games 2022? I. Haryana won the joint highest number of silver medals. II. Delhi won the second highest number of bronze medals.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Haryana won the joint highest number of silver medals (10) with Gujarat. Delhi won the highest (not second highest) number of bronze medals (12). Statement I is correct, II is incorrect.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '5c486b4c-2cbe-48b1-86ea-e596a5ae2a5b'::uuid, 2023, 'Paper-I', 'Who of the following won the Arjuna Awards 2022 in chess? I. Bhakti Pradip Kulkarni II. R Praggnanandhaa', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'R Praggnanandhaa won the Arjuna Award in 2022 for chess. Bhakti Pradip Kulkarni did not receive the award in 2022.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Normally rain water has a pH of ______.', '3.8', '4.2', '5.6', '6.4', 3, 'Normal rainwater has a pH of about 5.6 due to the presence of carbon dioxide forming carbonic acid. Lower pH indicates acid rain.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following constitutes the biotic component of the biosphere? I. Plants II. Air', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Plants are biotic (living) components of the biosphere. Air is abiotic (non-living). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Chlorofluorocarbons (CFCs)? I. CFCs are used in refrigerators, air conditioners, and aerosol sprays. II. CFCs damage the ozone layer in the atmosphere.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: CFCs are used in refrigerators, ACs, and aerosol sprays, and they deplete the ozone layer in the stratosphere.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following is a natural source of tartaric acid?', 'Tamarind', 'Tomato', 'Vinegar', 'Brinjal', 1, 'Tamarind is a natural source of tartaric acid. Vinegar contains acetic acid, tomatoes contain citric acid.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Anaemia is caused by the deficiency of ______.', 'Vitamin D', 'Phosphorus', 'Iodine', 'Iron', 4, 'Anaemia is caused by iron deficiency, which leads to reduced hemoglobin production and decreased oxygen-carrying capacity of blood.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding Mycoplasma? I. They completely lack a cell wall. II. They can survive without oxygen.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Mycoplasma lack a cell wall and can survive without oxygen (facultative anaerobes). Both statements are correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'What is the molecular formula of glucose?', 'C₆H₆O₁₂', 'C₆H₁₈O₁₂', 'C₆H₁₂O₁₈', 'C₆H₁₂O₆', 4, 'The molecular formula of glucose is C₆H₁₂O₆, representing six carbon, twelve hydrogen, and six oxygen atoms.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following is a main source of Vitamin C? I. Guava II. Egg', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Guava is a rich source of Vitamin C. Eggs do not contain significant amounts of Vitamin C. So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''substance – chemical formula'' is/are correctly matched? I. Washing soda – Na₂CO₃ II. Plaster of Paris – CaOCl₂', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Washing soda is Na₂CO₃ (correct). Plaster of Paris is CaSO₄·½H₂O, not CaOCl₂ (which is bleaching powder). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '7edb952a-3e62-4418-a9ca-56c0d12d7cf7'::uuid, 2023, 'Paper-I', 'Which of the following organisms belongs to the phylum Annelida? I. Scorpion II. Earthworm', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Earthworm belongs to phylum Annelida. Scorpion belongs to phylum Arthropoda (class Arachnida). So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'In August 1999, a High Powered Committee on Disaster Management was constituted under the Chairmanship of ______.', 'J.C. Pant', 'P.K. Sinha', 'A.K. Bhalla', 'D.S. Mishra', 1, 'The High Powered Committee on Disaster Management in August 1999 was chaired by J.C. Pant, which led to the Disaster Management Act.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'The Central Soil and Water Conservation Research and Training Institute is located in ______.', 'Chandigarh', 'Dehradun', 'Hyderabad', 'Bengaluru', 2, 'The Central Soil and Water Conservation Research and Training Institute is located in Dehradun, Uttarakhand.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is a natural hazard? I. Landslide II. Building collapse', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Landslide is a natural hazard caused by geological factors. Building collapse is a man-made hazard. So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'As per the final report of the High Powered Committee on Disaster management, which of the following is/are categorised under Geologically related Hazards? I. Droughts II. Earthquakes', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Earthquakes are geologically related hazards. Droughts are climatological hazards (water-related). So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'In India, about ______ percent of the landmass is prone to earthquakes of various intensities.', '40', '50', '60', '70', 3, 'About 60% of India''s landmass is prone to earthquakes of various intensities, with Zone V being the most active.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct in the context of major disasters in India since 1970? I. An earthquake of magnitude 6.6 killed more than 700 people in Uttarkashi on 20th October 1991. II. Approximately 8000 people died and there was a heavy loss to infrastructure in Latur on 30th September 1993.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Uttarkashi earthquake (1991, 6.6 magnitude) killed over 700 people, and Latur earthquake (1993) killed approximately 8000 people.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'The lowest region of atmosphere in which the human beings along with other organisms live is called ______.', 'Troposphere', 'Stratosphere', 'Thermosphere', 'Exosphere', 1, 'The troposphere is the lowest layer of the atmosphere where humans and most organisms live, extending from ground level up to about 12-15 km.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', '______ refers to the increase in concentration of toxins at successive trophic levels.', 'Biomagnification', 'Eutrophication', 'Detoxification', 'Bioremediation', 1, 'Biomagnification (or bioamplification) is the increase in concentration of toxins (like DDT, mercury) at successive trophic levels in a food chain.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is a greenhouse gas? I. Sulphur dioxide II. Carbon dioxide', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Carbon dioxide is a greenhouse gas. Sulphur dioxide is a pollutant but not a major greenhouse gas; it contributes to acid rain.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is/are correct regarding the consequence of deforestation? I. Soil erosion II. Desertification', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both soil erosion and desertification are major consequences of deforestation, as trees bind the soil and maintain the water cycle.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is/are correct regarding the greenhouse effect? I. It is a naturally occurring phenomenon responsible for heating of Earth''s surface and atmosphere. II. It is caused due to excessive accumulation of biodegradable substance in water system.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'The greenhouse effect is a natural phenomenon that warms the Earth. Statement II is incorrect; it describes eutrophication, not the greenhouse effect.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following is an advantage of CNG over petrol or diesel? I. Pipelines can be laid to supply CNG. II. CNG cannot be siphoned off like petrol or diesel.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'CNG cannot be siphoned off like petrol/diesel, making it more secure. Pipelines are not an advantage unique to CNG. So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, '77c5bae1-6709-42b9-b4db-a4e079fc6640'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the ''3R'' principle? I. Reduce is the first and most important principle of the 3R. II. Recycling involves using the same item repeatedly for the same purpose.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Reduce is the most important principle (prevention first). Recycling involves processing waste into new products, not using the same item repeatedly (which is reuse). So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'The outermost range of the Himalayas is called the ______.', 'Himadri', 'Shiwaliks', 'Himachal', 'Purvachal', 2, 'The outermost (southernmost) range of the Himalayas is the Shiwaliks (Siwalik Hills), also known as the Outer Himalayas.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Godavari river? I. It rises from the slopes of the Western Ghats in the Nasik district of Maharashtra. II. It drains into the Arabian Sea.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Godavari rises in Nasik, Maharashtra (Western Ghats). It drains into the Bay of Bengal, not the Arabian Sea. So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding alluvial soil? I. Old alluvial soil is called Khadar and new alluvial is called Bangar. II. Khadar is more fertile than the bangar.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 2, 'Statement I is reversed: Khadar is new alluvial soil, Bangar is old alluvial soil. Khadar is more fertile than Bangar. So Only II is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the northern plain of India? I. It has been formed by the interplay of the Indus, the Ganga and the Brahmaputra along with their tributaries. II. The plain is about 2400 km long.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: the northern plain is formed by the Indus, Ganga, Brahmaputra and their tributaries, and is approximately 2400 km long.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the climate of India? I. The cold weather season begins from mid November in northern India and stays till February. II. December and January are the coldest months in the northern part of India.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: cold weather season in north India runs from mid-November to February, with December and January being the coldest months.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following pairs of ''national park - state'' is/are correctly matched? I. Periyar Tiger Reserve - Kerala II. Manas Tiger Reserve - Odisha', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 1, 'Periyar Tiger Reserve is in Kerala (correct). Manas Tiger Reserve is in Assam, not Odisha. So Only I is correct.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'e587b482-1005-40dc-b6dd-3d9c2119a753'::uuid, 2023, 'Paper-I', 'Which of the following statements is/are correct regarding the Indus river system? I. The river Indus rises in Tibet, near Lake Mansarovar. II. The total length of the Indus is 3900 km.', 'Only I', 'Only II', 'Both I and II', 'Neither I nor II', 3, 'Both statements are correct: Indus rises in Tibet near Lake Mansarovar and has a total length of about 3900 km.', 'medium');
INSERT INTO public.questions (exam_id, subject_id, topic_id, year, paper, question_text, option_1, option_2, option_3, option_4, correct_option, explanation, difficulty) VALUES ('e33338c9-740c-48c4-914b-2cca3e9c1668'::uuid, 'aa8d32e0-c642-49ea-934c-af0f7fd9986a'::uuid, 'cee34a01-cf1d-4a36-8c58-9f3bc9960035'::uuid, 2023, 'Paper-I', 'Fundamental Duties of the citizens have also been enumerated in the Indian constitution by the ______.', '32nd Amendment', '34th Amendment', '42nd Amendment', '44th Amendment', 3, 'Fundamental Duties were added to the Indian Constitution by the 42nd Amendment Act, 1976, on the recommendation of the Swaran Singh Committee.', 'medium');
